bash_commands.command:
python -c "
import ast
import inspect

with open('tests/test_cache_middleware.py', 'r') as f:
    content = f.read()
    tree = ast.parse(content)

# Count test classes and methods
test_classes = []
test_methods = []

for node in ast.walk(tree):
    if isinstance(node, ast.ClassDef):
        if 'Test' in node.name:
            test_classes.append(node.name)
            for item in node.body:
                if isinstance(item, ast.FunctionDef) and item.name.startswith('test_'):
                    test_methods.append(f'{node.name}.{item.name}')

print(f'Test Classes: {len(test_classes)}')
for cls in test_classes:
    print(f'  - {cls}')

print(f'\nTest Methods: {len(test_methods)}')
for method in sorted(test_methods):
    print(f'  - {method}')
"

